/// <summary>
/// Command: disable an invite link so it can no longer accept RSVPs.
/// </summary>
/// <param name="LinkId">Invite link identifier.</param>
public sealed record DeactivateInviteLinkCommand(Guid LinkId) : IRequest<Unit>;

/// <summary>Handler for <see cref="DeactivateInviteLinkCommand"/>.</summary>
public sealed class DeactivateInviteLinkHandler : IRequestHandler<DeactivateInviteLinkCommand, Unit>
{
    private readonly ICurrentUserService _currentUser;
    private readonly AppDbContext _dbContext;

    /// <summary>Initializes a new instance of <see cref="DeactivateInviteLinkHandler"/>.</summary>
    public DeactivateInviteLinkHandler(ICurrentUserService currentUser, AppDbContext dbContext)
